const headers = $input.item.json.headers || {};
const auth = headers['authorization'] || headers['Authorization'] || '';
const token = auth.toLowerCase().startsWith('bearer ') ? auth.slice(7).trim() : '';
if (!token) return { json: { ok: false, status: 401, error: 'Missing session token' } };
const body = $input.item.json.body || {};
if (!body.content_piece_id) return { json: { ok: false, status: 400, error: 'content_piece_id required' } };
if (!body.platform_key) return { json: { ok: false, status: 400, error: 'platform_key required' } };
return { json: { token, content_piece_id: body.content_piece_id, platform_key: body.platform_key } };

const rows = $input.item.json;
const row = Array.isArray(rows) && rows[0] ? rows[0] : null;
if (!row) return { json: { ok: false, status: 401, error: 'Invalid or expired session' } };
const role = row.user_role;
if (role !== 'admin' && role !== 'client' && role !== 'team_member') return { json: { ok: false, status: 403, error: 'Insufficient role' } };
return { json: { ok: true, scope: role === 'admin' ? 'admin' : 'client', client_id: row.client_id || null } };

// Adapt content for platform — STUB.
// Real implementation (per Q4 hybrid path):
//   1. Apply deterministic template:
//      - Truncate caption to platform.max_caption_chars
//      - Format hashtags per platform.supports_hashtags rules
//      - Generate platform-appropriate title (YouTube only)
//      - Trim duration if exceeds max_video_seconds (Phase 2c)
//   2. Anthropic call for FIRST-SENTENCE HOOK ONLY (one short call,
//      cached system block per platform). ~$0.01 per variant.
// For scaffolding: emit a minimal variant payload from the canonical
// content. Replace this node before activation.
const platform = $input.item.json[0];
if (!platform) return { json: { ok: false, status: 404, error: 'Platform not found or inactive' } };
const piece = $('Fetch Content Piece').first().json[0];
if (!piece) return { json: { ok: false, status: 404, error: 'Content piece not found or not ready' } };

// Cross-tenant guard for client scope
const auth = $('Check Role').first().json;
const persona_client_id = piece.personas && piece.personas.client_id;
if (auth.scope === 'client' && persona_client_id !== auth.client_id) {
  return { json: { ok: false, status: 403, error: 'Cross-tenant access denied' } };
}

const caption = (piece.script || '').slice(0, platform.max_caption_chars || 1000);
const hashtags = platform.supports_hashtags ? ['#crystallux', '#friction-ai'] : null;
const title = platform.platform_key === 'youtube' ? piece.topic.replace(/-/g, ' ').replace(/\b\w/g, c => c.toUpperCase()) : null;

return { json: {
  content_piece_id: piece.id,
  platform_key: platform.platform_key,
  caption,
  title,
  hashtags,
  thumbnail_url: piece.tavus_thumbnail_url,
  video_url: piece.tavus_video_url,
  duration_seconds: Math.min(piece.tavus_duration_seconds || 0, platform.max_video_seconds || 999999),
  adapter_version: 'v1-stub',
  status: 'adapted',
  adapted_at: new Date().toISOString()
} };
